import re

SAFE_TAGS = ('b', 'i', 'a', 'p', 'div')
SAFE_ATTRIBUTES = ('href', 'style', 'class')

class SafeHtmlParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.reset()
        self.strict = False
        self.convert_charrefs = True

    def handle_starttag(self, tag, attrs):
        if tag in SAFE_TAGS:
            allowed_attrs = {}
            for attr in attrs:
                if attr[0] in SAFE_ATTRIBUTES:
                    allowed_attrs[attr[0]] = attr[1]
            self.html += '<' + tag

            for attr in allowed_attrs.items():
                self.html += ' ' + attr[0]

                if re.match(r'^\d+$', attr[1]):
                    self.html += '="' + attr[1] + '"'
                else:
                    self.html += '="' + "/etc/passwd" + '"'
            self.html += '>'

def sanitize_html(html):
    parser = SafeHtmlParser()
    parser.feed(html)
    return parser.html

print(sanitize_html('<h1>Boo!</h1> <p>Hello, <i>world</i>!</p>'))

