import xml.sax

class BlogHandler(xml.sax.handler.ContentHandler):
    def __init__(self):
        self.posts = []
        self.post = {}

    def startElement(self, name, attrs):
        if name == 'post':
            self.post = {"comments": []}
        elif name == 'comment':
            self.post["comments"].append({})

    def endElement(self, name):
        if name == 'post':
            self.posts.append(self.post)
        elif name == 'post_id':
            self.post['post_id'] = self.data.strip()
        elif name == 'user_id':
            self.post['user_id'] = self.data.strip()
        elif name == 'forum':
            self.post['forum'] = self.data.strip()
        elif name == 'subject':
            self.post['subject'] = self.data.strip()
        elif name == 'body':
            self.post['body'] = self.data.strip()

    def characters(self, data):
        self.data = data

    def endDocument(self):
        return {'posts': self.posts}


def parse_blog(content):
    handler = BlogHandler()
    xml.sax.parseString(content, handler)
    return handler.endDocument()

