from os import path

def check_dir(dir_name):
    if path.exists(dir_name):
        return True
    else:
        return False

def validate_input(file_path):
    home_dir = path.expanduser("~")

    try:
        full_path = path.join(home_dir, file_path)
    except AttributeError as e:
        return False

    if ".." in full_path:
        return False

    parent = path.dirname(full_path)

    if not check_dir(parent):
        return False

    return True

def read_file(file_path):
    validated_path = validate_input(file_path)
    if validated_path:
        with open(validated_path) as f:
            return f.read()
    else:
        return "Invalid input!"

