from template import check_marker, template


class TemplateEngine:

    @staticmethod
    def apply_marker(marker, string):
        return string.replace(marker, "Happy New Year")


    def convert(self, name):
        template_file = f"templates/{name}.tmpl"
        with open(template_file, 'rb') as f:
            template_content = pickle.load(f)

        replacements = self.get_replacements(name)
        for marker, replacement in replacements.items():
            template_content = TemplateEngine.apply_marker(marker, template_content)

        return template_content
