def filter_bad_words(text):
    allowed_words = ["star", "moon", "cloud", "sky"]

    sentences = text.split(".")
    bad_words = []

    for sentence in sentences:
        words = sentence.split(" ")
        for word in words:
            word = word.strip()
            if word not in allowed_words:
                bad_words.append(word)

    return bad_words

